## Language(en-US)

DOCUMENT();

############################################################
# Load Macros
############################################################
loadMacros(
  "PGstandard.pl",
  "PGML.pl",
  "AnswerFormatHelp.pl",
  "niceTables.pl",
  "PGchoicemacros.pl",
  "parserVectorUtils.pl",
  "contextForm.pl",
  "parserPopUp.pl",
  "PGcourse.pl",
);
COMMENT('Authored in PreTeXt');

############################################################
# Header
############################################################
TEXT(beginproblem());

############################################################
# PG Setup Code
############################################################
($actual_solution, $root) = num_sort((1..9)[NchooseK(9,2)]);
$square = $root**2;
$m = int($square / $actual_solution);
$b = $square % $actual_solution;
$left = Formula("sqrt($m x + $b)")->reduce;
$n = non_zero_random(-2,2);
$right = Formula("$n x");
$right += ($left->eval(x => $actual_solution) - $right->eval(x => $actual_solution) + (random(0,2) ? 0 : non_zero_random(-3,3)));
$right = $right->reduce;
($left, $right) = ($left, $right)[NchooseK(2,2)];
$proposed_solution = $actual_solution;
Context("LimitedNumeric");
$lefteval = Real($left->eval(x => $proposed_solution));
$righteval = Real($right->eval(x => $proposed_solution));
$inequality = list_random('\lt', '\gt', '\leq', '\geq', '\neq');
$truefalse = (
  ($inequality eq '\lt') ?
  ($lefteval < $righteval) :
  (
    ($inequality eq '\gt') ?
    ($lefteval > $righteval) :
    (
      ($inequality eq '\leq') ?
      ($lefteval <= $righteval) :
      (
        ($inequality eq '\geq') ?
        ($lefteval >= $righteval) :
        ($lefteval != $righteval)
      )
    )
  )
);
$dropdown = DropDown(["Yes, it is a solution.", "No, it is not a solution."], $truefalse ? 0 : 1, showInStatic => 0);

############################################################
# Body
############################################################

BEGIN_PGML
Check if the given number is a solution to the given inequality.

Is [`[$proposed_solution]`] a solution to [`[$left][$inequality][$right]\text{?}`]

>> [@DataTable(
  [
    [PGML('[`[$left->TeX]`]'),
     PGML('[`[$inequality]`]'),
     PGML('[`[$right->TeX]`]'),
    ],
    [PGML('[_]{$lefteval}{3}'),
     PGML('[`\wonder{[$inequality]}`]'),
     PGML('[_]{$righteval}{3}'),
    ],
  ],
      align => 'rcl',
      valign => 'middle',);@]* <<

[_]{$dropdown}{5}

END_PGML

############################################################
# End Problem
############################################################

ENDDOCUMENT();
